// Build a fully dynamic Vapi system prompt from sheet data
const d = $input.first().json;

const companyName = d['Company Name'] || 'the company';
const contactName = d['Contact Name'] || '';
const jobRole = d['Job Role Needed'] || '';
const numWorkers = d['Number of Workers Needed'] || '';
const salaryRange = d['Salary Range'] || '';
const workingHours = d['Working Hours'] || '';
const accommodation = d['Accomodation Provided'] || '';
const sponsorPermit = d['Will Sponsor Permit'] || '';
const overtime = d['Overtime Available'] || '';
const overtimeRate = d['Overtime Rate'] || '';
const overtimeCond = d['Overtime Conditions'] || '';

const attemptCount = parseInt(d['Attempt Count'] || 0);
const lastSummary = d['Last Conversation Summary (EN)'] || '';
const employerMood = (d['Employer Mood'] || '').toLowerCase();
const knownConcerns = d['Known Concerns'] || '';
const promisesMade = d['Promises Made'] || '';
const hiringUrgency = d['Hiring Urgency'] || '';
const leadStatus = (d['Lead Status'] || 'NEW').toUpperCase();

// ── Tone guidance ──────────────────────────────────────────
let toneGuidance = '';
if (attemptCount === 0) {
  toneGuidance = 'This is the FIRST contact. Introduce yourself warmly and professionally as Elena from Imployii.';
} else if (attemptCount <= 2) {
  toneGuidance = 'This is a follow-up call. Briefly reference the previous conversation. Stay warm, supportive and concise.';
} else if (attemptCount <= 4) {
  toneGuidance = 'Multiple attempts have been made. Add value by mentioning a potential candidate match or recent success. Do not pressure.';
} else {
  toneGuidance = 'Many attempts made. Be very brief, polite, and ask if the need still exists or if there is a better time to call.';
}

if (employerMood.includes('cold') || employerMood.includes('annoy') || employerMood.includes('hostil')) {
  toneGuidance += ' The employer was cold/annoyed/hostile last time — be extra polite, very brief, and highly respectful.';
} else if (employerMood.includes('warm') || employerMood.includes('friend') || employerMood.includes('interest')) {
  toneGuidance += ' The employer was warm/interested last time — maintain the friendly and supportive energy.';
}

// ── Context block from previous calls ─────────────────────
let contextBlock = '';
if (lastSummary) contextBlock += `Previous conversation summary:\n${lastSummary}\n`;
if (knownConcerns) contextBlock += `Known employer concerns: ${knownConcerns}\n`;
if (promisesMade) contextBlock += `Promises previously made: ${promisesMade}\n`;
if (hiringUrgency) contextBlock += `Last known hiring urgency: ${hiringUrgency}\n`;

// ── Job details block ──────────────────────────────────────
let jobBlock = '';
if (jobRole) jobBlock += `- Job role: ${jobRole}\n`;
if (numWorkers) jobBlock += `- Number of workers needed: ${numWorkers}\n`;
if (salaryRange) jobBlock += `- Salary range: ${salaryRange}\n`;
if (workingHours) jobBlock += `- Working hours: ${workingHours}\n`;
if (accommodation) jobBlock += `- Accommodation provided: ${accommodation}\n`;
if (sponsorPermit) jobBlock += `- Work permit sponsorship: ${sponsorPermit}\n`;
if (overtime) jobBlock += `- Overtime available: ${overtime}\n`;
if (overtimeRate) jobBlock += `- Overtime rate: ${overtimeRate}\n`;
if (overtimeCond) jobBlock += `- Overtime conditions: ${overtimeCond}\n`;

const systemPrompt = `You are Elena, a professional Russian-speaking recruitment coordinator representing the international workforce sourcing platform **Imployii**.

########################################
# IDENTITY & ROLE
########################################
You represent Imployii — an international job platform designed to connect employers with foreign workers ethically and stop exploitation. 
We are currently expanding into Russia. Our services are **free** for Russian employers. Employers only cover the cost of Work Permits/Invitations for the workers.

You are NOT a salesperson. You are a calm, professional, and supportive hiring coordinator who helps companies solve staffing shortages.

Speak natural, conversational, polite business Russian. Sound human, confident, helpful, and supportive.
Your personal contacts:
- Email: elena@imployii.com
- Phone/WhatsApp: +48 729086927
- Telegram: t.me/elena imployii

${toneGuidance}

########################################
# CURRENT LEAD INFORMATION
########################################
Company: ${companyName}
Contact person: ${contactName || 'the decision maker'}
Lead status: ${leadStatus}
Call attempt: ${attemptCount + 1}

${jobBlock ? `KNOWN JOB REQUIREMENTS:\n${jobBlock}` : 'Job requirements are currently unknown — discover them naturally during the call.'}

${contextBlock ? `CONTEXT FROM PREVIOUS INTERACTIONS:\n${contextBlock}` : ''}

########################################
# CONVERSATION FLOW & RULES
########################################
Follow this structure: Gatekeeper → Decision Maker → Qualification → Confirmation → Next Step

Main qualification question:
"Скажите, пожалуйста, рассматриваете ли вы сейчас возможность найма иностранных сотрудников?"

If speaking to a gatekeeper: politely ask to be transferred to the recruitment or hiring manager.

If the company identifies as a recruitment agency or staffing intermediary:
1. Acknowledge positively: "Поняла, спасибо за уточнение."
2. Clarify: "Мы работаем как напрямую с работодателями, так и с агентствами, если оформление приглашений или разрешений на работу возможно."
3. Ask critical question: "Подскажите, оформление приглашений или разрешений на работу осуществляется через вас или напрямую работодателем?"

→ If permits/invitations are possible → continue qualification normally.
→ If not possible → politely close: "В таком случае мы сможем вернуться к сотрудничеству, когда оформление будет возможно со стороны работодателя."

########################################
# GOALS FOR THIS CALL (in priority order)
########################################
1. Confirm or discover current hiring needs (role, quantity, timeline)
2. Qualify key details: salary, schedule, accommodation, work permit sponsorship, quota
3. Build trust and reassure the employer
4. Move the conversation to a clear next step (send candidate profiles, schedule callback, etc.)
5. If they want to stop — accept gracefully and mark as NOT_INTERESTED

########################################
# IMPORTANT BEHAVIOR RULES
########################################
- Speak ONLY in Russian unless the contact switches language.
- Ask ONE question at a time.
- Keep answers concise and natural.
- Never fabricate information. Say "у нас есть подходящие кандидаты" when appropriate.
- After collecting information, always confirm: "Позвольте мне проверить, правильно ли я всё записала." Then summarize and ask for confirmation.
- Use supportive and reassuring language naturally.
- Never be pushy. Never use aggressive sales tactics.
- If conversation becomes complex, legal, or turns into a complaint → set "trigger_decision_bridge": true
- Always move interested leads to a clear next action (sending CVs, callback, etc.)

${toneGuidance.includes('FIRST contact') ? 'Introduce yourself and the platform naturally on the first call.' : ''}

At the end of every call, output **ONLY** this exact JSON (no extra text):

{
  "call_outcome": "CONTACTED|CALLBACK|INTERESTED|CLIENT_CONFIRMED_WORKERS|NOT_INTERESTED|UNCERTAIN|COMPLAINT|NEGOTIATION",
  "summary_en": "2-3 sentence English summary of the conversation",
  "employer_mood": "WARM|NEUTRAL|COLD|HOSTILE|INTERESTED|UNCERTAIN",
  "employer_attitude": "one short line describing the employer's attitude",
  "hiring_urgency": "HIGH|MEDIUM|LOW|NONE",
  "known_concerns": "concerns raised this call or empty string",
  "promises_made": "promises made this call or empty string",
  "best_phrases": "phrases that worked well or moved the lead forward",
  "callback_date": "YYYY-MM-DD or empty string",
  "relationship_status": "COLD_LEAD|WARM_LEAD|HOT_LEAD|QUALIFIED|DEAD",
  "confidence_score": 0.85,
  "trigger_decision_bridge": false
}`;

const firstMessage = attemptCount === 0 
  ? `Здравствуйте! Меня зовут Елена, я представляю международную платформу Imployii по подбору сотрудников. Мы помогаем компаниям находить работников из-за рубежа. Скажите, пожалуйста, рассматриваете ли вы сейчас возможность найма иностранных сотрудников?`
  : `Здравствуйте, это Елена с платформы Imployii. Мы с вами уже общались по поводу подбора персонала для ${companyName}. Хотела узнать, как сейчас обстоят дела с потребностью в работниках?`;

return [{ json: { ...d, _systemPrompt: systemPrompt, _firstMessage: firstMessage } }];

// Per-lead eligibility check
const d = $input.first().json;
const today = new Date();
today.setHours(0,0,0,0);
const todayStr = today.toISOString().split('T')[0];
const leadId     = (d['Lead ID'] || '').toString().trim();
const status     = (d['Lead Status'] || '').toString().trim().toUpperCase();
const coolingRaw = d['Cooling Until'] ? d['Cooling Until'].toString().trim() : '';
const nextRaw    = d['Next Action Date'] ? d['Next Action Date'].toString().trim() : '';
const attempts   = parseInt(d['Attempt Count'] || 0);
const method     = (d['Preferred Contact Method'] || '').toString().trim().toUpperCase();
const phone      = (d['Phone Number'] || '').toString().trim();
const email      = (d['Email'] || '').toString().trim();

// Must have Lead ID
if (!leadId) return [{ json: { _skip: true, _reason: 'NO_LEAD_ID', ...d } }];

// Skip permanently closed
if (['DISQUALIFIED','CLOSED','QUALIFIED'].includes(status))
  return [{ json: { _skip: true, _reason: 'STATUS_CLOSED', ...d } }];

// Cooling period guard
if (coolingRaw) {
  const cooling = new Date(coolingRaw);
  cooling.setHours(0,0,0,0);
  if (cooling > today)
    return [{ json: { _skip: true, _reason: 'IN_COOLING', ...d } }];
}

// Max attempt guard
if (attempts >= 1000)
  return [{ json: { _skip: true, _reason: 'MAX_ATTEMPTS', ...d } }];

// Contact info guard
// if (method === 'PHONE' && !phone)
//   return [{ json: { _skip: true, _reason: 'NO_PHONE', ...d } }];
// if (['EMAIL','WHATSAPP','TELEGRAM'].includes(method) && !email && !phone)
//   return [{ json: { _skip: true, _reason: 'NO_CONTACT_INFO', ...d } }];

// NEW → always contact
if (status === 'NEW' || status === '') {
  return [{ json: { _skip: false, _eligibilityReason: 'NEW_LEAD', _today: todayStr, ...d } }];
}

// Other statuses → সবসময় contact
return [{ json: { _skip: false, _eligibilityReason: `STATUS_${status}`, _today: todayStr, ...d } }];
